'use client';

import { useState, useEffect, useCallback, useMemo } from 'react';
import { motion } from 'framer-motion';
import dynamic from 'next/dynamic';
import { MovebankStudy, AnimalTrack } from '../types/movebank';
import { movebankService } from '../services/movebank';
import StudySelector from '../components/ui/StudySelector';
import AnimalProfile from '../components/ui/AnimalProfile';
import AlertsPanel from '../components/ui/AlertsPanel';
import ComparisonPanel from '../components/ui/ComparisonPanel';
import Charts from '../components/ui/Charts';
import PlaybackControls from '../components/ui/PlaybackControls';
import { exportToCSV, exportToJSON, exportToGeoJSON } from '../lib/export';

const Globe = dynamic(() => import('../components/globe/Globe'), {
  ssr: false,
  loading: () => (
    <div className="w-full h-full flex items-center justify-center text-white">
      <motion.div
        animate={{ rotate: 360 }}
        transition={{ duration: 2, repeat: Infinity, ease: 'linear' }}
        className="text-4xl"
      >
        🌍
      </motion.div>
    </div>
  ),
});

const DEFAULT_STUDY_ID = 2911040;

export default function Home() {
  const [studies, setStudies] = useState<MovebankStudy[]>([]);
  const [selectedStudyIds, setSelectedStudyIds] = useState<number[]>([]);
  const [animalTracks, setAnimalTracks] = useState<AnimalTrack[]>([]);
  const [selectedAnimal, setSelectedAnimal] = useState<string | null>(null);
  const [comparisonMode, setComparisonMode] = useState(false);
  const [comparisonAnimals, setComparisonAnimals] = useState<Set<string>>(new Set());
  const [showCities, setShowCities] = useState(true);
  const [showAlerts, setShowAlerts] = useState(false);
  const [loading, setLoading] = useState(true);
  const [playbackProgress, setPlaybackProgress] = useState(1);
  const [isPlaying, setIsPlaying] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedSpecies, setSelectedSpecies] = useState<string>('');

  useEffect(() => {
    loadStudies();
    setSelectedStudyIds([DEFAULT_STUDY_ID]);
    loadStudyData([DEFAULT_STUDY_ID]);
  }, []);

  useEffect(() => {
    let interval: NodeJS.Timeout;
    if (isPlaying && playbackProgress < 1) {
      interval = setInterval(() => {
        setPlaybackProgress(prev => Math.min(prev + 0.005, 1));
      }, 50);
    } else if (playbackProgress >= 1) {
      setIsPlaying(false);
    }
    return () => clearInterval(interval);
  }, [isPlaying, playbackProgress]);

  async function loadStudies() {
    try {
      const res = await fetch('/api/movebank/studies?limit=50');
      const publicStudies = await res.json();
      setStudies(publicStudies);
    } catch (error) {
      console.error('Failed to load studies:', error);
    }
  }

  async function loadStudyData(studyIds: number[]) {
    setLoading(true);
    try {
      const allTracks: AnimalTrack[] = [];
      for (const studyId of studyIds) {
        const res = await fetch(`/api/movebank/study-events?studyId=${studyId}&limit=2000`);
        if (!res.ok) {
          console.error(`API error for study ${studyId}: ${res.status}`);
          continue;
        }
        const events = await res.json();
        if (!Array.isArray(events)) {
          console.error(`Expected array for study ${studyId}, got:`, events);
          continue;
        }
        const tracks = movebankService.transformToAnimalTracks(events);
        const tracksWithStudy = tracks.map(track => ({
          ...track,
          animalId: `${studyId}-${track.animalId}`,
          animalName: `${track.animalName} (Study: ${studies.find(s => s.id === studyId)?.name || studyId})`
        }));
        allTracks.push(...tracksWithStudy);
      }
      setAnimalTracks(allTracks);
      setSelectedAnimal(null);
      setPlaybackProgress(1);
      setIsPlaying(false);
    } catch (error) {
      console.error('Failed to load study data:', error);
    } finally {
      setLoading(false);
    }
  }

  const handleStudySelect = useCallback((studyId: number) => {
    setSelectedStudyIds(prev => {
      const newIds = prev.includes(studyId)
        ? prev.filter(id => id !== studyId)
        : [...prev, studyId];
      loadStudyData(newIds);
      return newIds;
    });
  }, []);

  const handlePlayPause = useCallback(() => {
    if (playbackProgress >= 1) {
      setPlaybackProgress(0);
    }
    setIsPlaying(prev => !prev);
  }, [playbackProgress]);

  const handleProgressChange = useCallback((value: number) => {
    setPlaybackProgress(value);
    setIsPlaying(false);
  }, []);

  const handleAnimalClick = useCallback((track: AnimalTrack) => {
    if (comparisonMode) {
      setComparisonAnimals(prev => {
        const next = new Set(prev);
        if (next.has(track.animalId)) next.delete(track.animalId);
        else next.add(track.animalId);
        return next;
      });
    } else {
      setSelectedAnimal(track.animalId);
    }
  }, [comparisonMode]);

  const speciesList = useMemo(() => {
    const species = new Set(animalTracks.map(t => t.species).filter(Boolean));
    return Array.from(species);
  }, [animalTracks]);

  const filteredTracks = useMemo(() => {
    return animalTracks.filter(track => {
      if (searchTerm && !track.animalName.toLowerCase().includes(searchTerm.toLowerCase())) return false;
      if (selectedSpecies && track.species !== selectedSpecies) return false;
      return true;
    });
  }, [animalTracks, searchTerm, selectedSpecies]);

  const selectedTrack = filteredTracks.find(t => t.animalId === selectedAnimal) || null;
  const startDate = selectedTrack?.points[0]?.timestamp || '';
  const endDate = selectedTrack?.points[selectedTrack.points.length - 1]?.timestamp || '';

  return (
    <main className="w-full h-screen bg-[#0a0a1a] relative overflow-hidden">
      <div className="absolute inset-0 z-0">
        {loading ? (
          <div className="w-full h-full flex items-center justify-center text-white">
            <motion.div
              animate={{ opacity: [0.5, 1, 0.5] }}
              transition={{ duration: 1.5, repeat: Infinity }}
              className="text-xl"
            >
              Loading wildlife tracking data...
            </motion.div>
          </div>
        ) : (
          <Globe
            animalTracks={filteredTracks}
            selectedAnimal={selectedAnimal}
            onAnimalSelect={setSelectedAnimal}
            playbackProgress={playbackProgress}
            showCities={showCities}
          />
        )}
      </div>

      <div className="absolute top-6 left-6 z-10 space-y-3">
        <StudySelector
          studies={studies}
          selectedStudyIds={selectedStudyIds}
          onStudySelect={handleStudySelect}
          loading={loading}
        />

        {selectedTrack && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
          >
            <Charts track={selectedTrack} playbackProgress={playbackProgress} />
          </motion.div>
        )}

        {comparisonMode && comparisonAnimals.size >= 2 && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
          >
            <ComparisonPanel
              tracks={filteredTracks.filter(t => comparisonAnimals.has(t.animalId))}
            />
          </motion.div>
        )}

        {showAlerts && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
          >
            <AlertsPanel
              tracks={filteredTracks}
              onClose={() => setShowAlerts(false)}
            />
          </motion.div>
        )}
      </div>

      <div className="absolute top-6 right-6 z-10 space-y-3">
        <AnimalProfile
          track={selectedTrack}
          onClose={() => setSelectedAnimal(null)}
          playbackProgress={playbackProgress}
        />
      </div>

      <div className="absolute bottom-6 left-1/2 -translate-x-1/2 z-10">
        <PlaybackControls
          isPlaying={isPlaying}
          progress={playbackProgress}
          onPlayPause={handlePlayPause}
          onProgressChange={handleProgressChange}
          currentTime={selectedTrack?.points[Math.floor(selectedTrack.points.length * playbackProgress)]?.timestamp ? new Date(selectedTrack.points[Math.floor(selectedTrack.points.length * playbackProgress)].timestamp).toLocaleTimeString() : '--:--:--'}
          totalTime={selectedTrack?.points[selectedTrack.points.length - 1]?.timestamp ? new Date(selectedTrack.points[selectedTrack.points.length - 1].timestamp).toLocaleTimeString() : '--:--:--'}
          startDate={startDate}
          endDate={endDate}
        />
      </div>

      <div className="absolute bottom-6 right-6 z-10">
        <motion.div
          initial={{ opacity: 0, x: 50 }}
          animate={{ opacity: 1, x: 0 }}
          transition={{ delay: 0.3 }}
          className="glass-panel p-3 rounded-xl text-white text-xs"
        >
          <div className="flex items-center justify-between mb-2">
            <div className="font-bold text-blue-400">Animal Tracks ({filteredTracks.length})</div>
            <div className="flex gap-2">
              <button
                onClick={() => setShowAlerts(!showAlerts)}
                className={`px-2 py-1 rounded text-xs transition-colors ${
                  showAlerts 
                    ? 'bg-red-500/50 text-white border border-red-400' 
                    : 'bg-black/50 text-white/70 border border-white/20'
                }`}
              >
                🚨 {showAlerts ? 'ON' : 'OFF'}
              </button>
              <button
                onClick={() => setComparisonMode(!comparisonMode)}
                className={`px-2 py-1 rounded text-xs transition-colors ${
                  comparisonMode 
                    ? 'bg-purple-500/50 text-white border border-purple-400' 
                    : 'bg-white/10 hover:bg-white/20 border border-white/20'
                }`}
              >
                Compare {comparisonAnimals.size > 0 && `(${comparisonAnimals.size})`}
              </button>
            </div>
          </div>

           <div className="flex gap-1 mb-2">
             <button
               onClick={() => exportToCSV(filteredTracks)}
               className="px-2 py-1 bg-blue-500/30 hover:bg-blue-500/50 rounded text-xs transition-colors"
             >
               CSV
             </button>
             <button
               onClick={() => exportToJSON(filteredTracks)}
               className="px-2 py-1 bg-green-500/30 hover:bg-green-500/50 rounded text-xs transition-colors"
             >
               JSON
             </button>
             <button
               onClick={() => exportToGeoJSON(filteredTracks)}
               className="px-2 py-1 bg-purple-500/30 hover:bg-purple-500/50 rounded text-xs transition-colors"
             >
               GeoJSON
             </button>
           </div>

           {speciesList.length > 1 && (
            <select
              value={selectedSpecies}
              onChange={(e) => setSelectedSpecies(e.target.value)}
              className="w-full bg-white/10 border border-white/20 rounded px-2 py-1 text-xs mb-2 focus:outline-none"
            >
              <option value="">All Species</option>
              {speciesList.map(s => (
                <option key={s} value={s}>{s}</option>
              ))}
            </select>
          )}

          {filteredTracks.slice(0, 8).map(track => (
            <motion.div
              key={track.animalId}
              whileHover={{ scale: 1.05 }}
              className="flex items-center gap-2 py-1 cursor-pointer"
              onClick={() => handleAnimalClick(track)}
            >
              {comparisonMode ? (
                <input
                  type="checkbox"
                  checked={comparisonAnimals.has(track.animalId)}
                  readOnly
                  className="rounded border-white/20"
                />
              ) : (
                <div
                  className="w-3 h-3 rounded-full"
                  style={{ backgroundColor: track.color, boxShadow: `0 0 8px ${track.color}` }}
                />
              )}
              <span className="text-gray-300 text-xs truncate">{track.animalName}</span>
            </motion.div>
          ))}

          {filteredTracks.length > 8 && (
            <div className="text-gray-500 text-xs mt-1">+{filteredTracks.length - 8} more</div>
          )}
        </motion.div>
      </div>

      <motion.div
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.7 }}
        className="absolute top-6 left-1/2 -translate-x-1/2 z-10"
      >
        <h1 className="text-2xl font-bold text-white tracking-wide" style={{ textShadow: '0 0 20px rgba(0,136,255,0.8), 0 0 40px rgba(0,136,255,0.4)' }}>
          Wildlife Tracking Dashboard
        </h1>
      </motion.div>
    </main>
  );
}
