'use client';

import { motion } from 'framer-motion';

interface PlaybackControlsProps {
  isPlaying: boolean;
  progress: number;
  onPlayPause: () => void;
  onProgressChange: (value: number) => void;
  currentTime: string;
  totalTime: string;
  startDate?: string;
  endDate?: string;
  onDateRangeChange?: (start: string, end: string) => void;
}

export default function PlaybackControls({
  isPlaying,
  progress,
  onPlayPause,
  onProgressChange,
  currentTime,
  totalTime,
  startDate,
  endDate,
}: PlaybackControlsProps) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 50 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.5, delay: 0.2 }}
      className="glass-panel p-4 rounded-2xl w-full max-w-2xl text-white"
    >
      <div className="flex items-center gap-4 mb-3">
        <motion.button
          whileHover={{ scale: 1.1 }}
          whileTap={{ scale: 0.95 }}
          onClick={onPlayPause}
          className="w-12 h-12 rounded-full bg-gradient-to-r from-blue-500 to-cyan-500 hover:from-blue-600 hover:to-cyan-600 flex items-center justify-center text-xl shadow-lg shadow-blue-500/30 transition-all"
        >
          {isPlaying ? '⏸' : '▶'}
        </motion.button>

        <div className="flex-1">
          <input
            type="range"
            min="0"
            max="100"
            value={progress * 100}
            onChange={(e) => onProgressChange(parseFloat(e.target.value) / 100)}
            className="w-full accent-blue-500 cursor-pointer"
          />
        </div>

        <div className="text-sm text-gray-300 min-w-[120px] text-right font-mono">
          {currentTime} / {totalTime}
        </div>
      </div>

      {(startDate || endDate) && (
        <div className="flex items-center justify-center gap-4 text-xs text-gray-400 mb-2">
          {startDate && (
            <span>From: {new Date(startDate).toLocaleDateString()}</span>
          )}
          {endDate && (
            <span>To: {new Date(endDate).toLocaleDateString()}</span>
          )}
        </div>
      )}

      <div className="text-xs text-gray-400 text-center">
        Tracking Playback • Drag slider or press play to animate
      </div>
    </motion.div>
  );
}
